from kafka import KafkaProducer
from flask import Flask, request, jsonify
import json
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Initialize Kafka producer
producer = KafkaProducer(
    bootstrap_servers='localhost:9092',
    value_serializer=lambda v: json.dumps(v).encode('utf-8'),
    key_serializer=lambda k: json.dumps(k).encode('utf-8') if k is not None else None,
    api_version=(0, 10, 2)
)

@app.route('/publish', methods=['POST'])
def publish_message():
    try:
        # Get topic name from request parameters
        topic_name = request.args.get('topic')
        
        if not topic_name:
            return jsonify({'error': 'Topic name is required'}), 400
            
        # Validate topic name (basic validation)
        if not isinstance(topic_name, str) or not topic_name.strip():
            return jsonify({'error': 'Invalid topic name'}), 400
            
        # Sanitize topic name
        topic_name = topic_name.strip()
        
        # Get message from request body
        message_data = request.get_json()
        
        if not message_data:
            return jsonify({'error': 'Message data is required'}), 400
            
        # Send message to Kafka
        future = producer.send(topic_name, message_data)
        producer.flush()
        
        # Get the result
        result = future.get(timeout=10)
        
        logger.info(f"Message published to topic {topic_name}")
        return jsonify({'status': 'success', 'topic': topic_name}), 200
        
    except Exception as e:
        logger.error(f"Error publishing message: {str(e)}")
        return jsonify({'error': 'Failed to publish message'}), 500

@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({'status': 'healthy'}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)